const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();

exports.criarPerfilDevEstudos = functions.auth.user().onCreate(async (user) => {
  await admin.firestore().collection('perfis').doc(user.uid).set({
    email: user.email,
    nome: user.displayName || 'Aluno',
    xp: 0,
    criadoEm: admin.firestore.FieldValue.serverTimestamp()
  });
});

